// pages/DetailProductPage.jsx
"use client";

import { useParams, useNavigate } from "react-router-dom";
import { useState, useEffect } from "react";
import Navbar from "../navbar";
import Footer from "../footer";
import CartSidebarWrapper from "../shopcart/CartSidebarWrapper";

export default function DetailProductPage({ products }) {
    const { id } = useParams(); // id จาก url /product/:id
    const navigate = useNavigate();

    const [product, setProduct] = useState(null);
    const [isCartOpen, setIsCartOpen] = useState(false);
    const [cartItems, setCartItems] = useState([]);

    useEffect(() => {
        const found = products.find(p => p.id === parseInt(id));
        if (found) setProduct(found);
        else navigate("/"); // ถ้าไม่เจอสินค้า กลับหน้า Home
    }, [id, products, navigate]);

    const addToCart = (item) => {
        const exist = cartItems.find(c => c.id === item.id);
        if (exist) {
            setCartItems(prev =>
                prev.map(c => c.id === item.id ? { ...c, qty: c.qty + 1 } : c)
            );
        } else {
            setCartItems(prev => [...prev, { ...item, qty: 1, stock: 10 }]);
        }
    };

    if (!product) return null;

    return (
        <div className="font-sans bg-white relative">
            <Navbar cartItems={cartItems} onCartOpen={() => setIsCartOpen(true)} />

            <main className="max-w-7xl mx-auto px-6 py-6">
                {/* Breadcrumb */}
                <div className="text-sm text-gray-500 mb-4">
                    <span className="cursor-pointer hover:text-green-600" onClick={() => navigate("/")}>Home</span> / {product.category} / {product.name}
                </div>

                <div className="flex flex-col lg:flex-row gap-6">
                    {/* Product Image */}
                    <div className="flex flex-col gap-2">
                        <img src={product.image} alt={product.name} className="w-80 h-80 object-contain" />
                        <div className="flex gap-2">
                            {/* ตัวอย่างรูปเสริม */}
                            <img src={product.image} alt="thumb1" className="w-20 h-20 object-contain border" />
                            <img src={product.image} alt="thumb2" className="w-20 h-20 object-contain border" />
                        </div>
                    </div>

                    {/* Product Info */}
                    <div className="flex-1">
                        <p className="text-green-600 font-medium">{product.category}</p>
                        <h1 className="text-2xl font-semibold">{product.name}</h1>
                        <p className="text-xl text-gray-800 mt-2">${product.price.toFixed(2)}</p>

                        {/* Quantity & Add */}
                        <div className="flex items-center mt-4 gap-2">
                            <button
                                onClick={() => addToCart(product)}
                                className="bg-green-600 text-white px-4 py-2 rounded hover:bg-green-700"
                            >
                                Add to cart
                            </button>
                            <button className="border px-3 py-1 rounded">♥</button>
                        </div>

                        {/* Product Details */}
                        <div className="mt-6">
                            <h3 className="font-semibold text-lg mb-2">Product Details</h3>
                            <p>Benefits: {product.desc}</p>
                            <p>Product code: P{product.id.toString().padStart(5, '0')}</p>
                            <p className="text-green-600 mt-1">In stock: 2500</p>
                            <p>Type: {product.category}</p>
                            <p>Shipping: 01/01/2025</p>
                        </div>
                    </div>
                </div>

                {/* Related Items */}
                <div className="mt-8">
                    <h3 className="font-semibold mb-4">Related Items</h3>
                    <div className="grid grid-cols-4 gap-4">
                        {products.filter(p => p.category === product.category && p.id !== product.id).map(p => (
                            <div key={p.id} className="border p-2 rounded">
                                <img src={p.image} alt={p.name} className="w-full h-32 object-contain" />
                                <p className="text-sm">{p.name}</p>
                                <p className="text-sm font-semibold">${p.price.toFixed(2)}</p>
                                <button
                                    onClick={() => navigate(`/product/${p.id}`)}
                                    className="bg-green-600 text-white text-xs px-2 py-1 rounded mt-1"
                                >
                                    + Add
                                </button>
                            </div>
                        ))}
                    </div>
                </div>
            </main>

            <Footer />

            <CartSidebarWrapper
                isCartOpen={isCartOpen}
                onClose={() => setIsCartOpen(false)}
                cartItems={cartItems}
                increaseQty={() => {}}
                decreaseQty={() => {}}
                removeItem={() => {}}
            />
        </div>
    );
}
